  ('disabled-7fec267e-moex-00107', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '對於「行政」意涵不同切入觀點之敘述，下列何者正確？', '["政治的觀點認為「行政」探討行政院之作為即可", "管理的觀點關注於探討有效處理公務之方法和技術", "公共政策的觀點不探討政府選擇不作為之事項", "公共性的觀點主要源自於新公共管理論述之啟發"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
